esqlQuery.esql:
FROM metrics-oracledbreceiver.otel-*
// Sessions usage is split by session_type/session_status; limit is separate document group
// First aggregate per-timestamp to get total sessions at each scrape point
| STATS sessions_at_ts = SUM(oracledb.sessions.usage),
        limit_val = MAX(oracledb.sessions.limit)
        BY @timestamp, oracledb.instance.name, host.name
// Then take peak sessions across the time window
| STATS peak_sessions = MAX(sessions_at_ts),
        limit_val = MAX(limit_val)
        BY oracledb.instance.name, host.name
| WHERE limit_val > 0
// Utilisation threshold: 85% — approaching session limit prevents new connections
// Adjust threshold to tune sensitivity
| EVAL utilisation_pct = ROUND(peak_sessions * 100.0 / limit_val, 1)
| WHERE utilisation_pct > 85
| SORT utilisation_pct DESC
